			await vi.waitFor(() => {
				expect(document.querySelector('.chat ul')!.querySelectorAll('li').length).toBe(
					countBefore + 1
				);
			});

			// Scroll position should remain near the top — lock must not have fired
			expect(msgList.scrollTop).toBeLessThan(16);
		});
	});
});

